            "claude-opus-*,200000,92,80\n"
            "claude-haiku-*,200000,92,80\n"
            "claude-fable-5*,1000000,92,80\n"
            "claude-fable-*,200000,92,80\n"
            "claude-4*,200000,92,80\n"
            "claude-3*,200000,92,80\n"
