# === owui_manifolds/shared/history_store.py ===
import inspect
import time
from typing import Any



async def maybe_await(value: Any) -> Any:
    if inspect.isawaitable(value):
        return await value
    return value


class OpenWebUIItemStore:
    def __init__(
        self,
        *,
        root_key: str,
        version: int = 1,
        chats_model: Any | None = None,
    ):
        self.root_key = root_key
        self.version = version
        self._Chats = chats_model if chats_model is not None else import_chats()

    async def save_item(
        self,
        chat_id: str | None,
        payload: dict[str, Any],
        *,
        model_id: str | None = None,
        message_id: str | None = None,
        ulid: str | None = None,
    ) -> str | None:
        if not self._Chats or not chat_id:
            return None
        chat = await maybe_await(self._Chats.get_chat_by_id(chat_id))
        if not chat:
            return None
        item_id = ulid or generate_ulid()
        root = chat.chat.setdefault(self.root_key, {"__v": self.version})
        items = root.setdefault("items", {})
        stored: dict[str, Any] = {
            "created_at": int(time.time()),
            "payload": payload,
        }
        if model_id is not None:
            stored["model"] = model_id
        if message_id is not None:
            stored["message_id"] = message_id
            bucket = root.setdefault("messages_index", {}).setdefault(
                message_id,
                {"role": "assistant", "done": True, "item_ids": []},
            )
            bucket.setdefault("item_ids", []).append(item_id)
        items[item_id] = stored
        await maybe_await(self._Chats.update_chat_by_id(chat_id, chat.chat))
        return item_id

    async def save_items(
        self,
        chat_id: str | None,
        payloads: list[dict[str, Any]],
        *,
        model_id: str | None = None,
        message_id: str | None = None,
    ) -> list[str]:
        created: list[str] = []
        for payload in payloads:
            item_id = await self.save_item(
                chat_id,
                payload,
                model_id=model_id,
                message_id=message_id,
            )
            if item_id:
                created.append(item_id)
        return created

    async def load_item(
        self,
        chat_id: str | None,
        ulid: str,
        *,
        model_id: str | None = None,
    ) -> dict[str, Any] | None:
        if not self._Chats or not chat_id or not ulid:
            return None
        chat = await maybe_await(self._Chats.get_chat_by_id(chat_id))
        if not chat:
            return None
        item = chat.chat.get(self.root_key, {}).get("items", {}).get(ulid)
        if not isinstance(item, dict):
            return None
        if model_id is not None and item.get("model") != model_id:
            return None
        payload = item.get("payload")
        return payload if isinstance(payload, dict) else None

    async def load_items(
        self,
        chat_id: str | None,
        item_ids: list[str],
        *,
        model_id: str | None = None,
    ) -> dict[str, dict[str, Any]]:
        loaded: dict[str, dict[str, Any]] = {}
        for item_id in item_ids:
            payload = await self.load_item(chat_id, item_id, model_id=model_id)
            if payload is not None:
                loaded[item_id] = payload
        return loaded


__all__ = ["OpenWebUIItemStore", "maybe_await"]

# === owui_manifolds/shared/rendering.py ===
import html
import json
import re
from typing import Any

TOOL_CALLS_DETAILS_RE = re.compile(
    r'\n?<details type="tool_calls"[^>]*>.*?</details>\n?',
    flags=re.DOTALL,
)
TOOL_CALLS_BLOCK_RE = re.compile(
    r'\n?<details type="tool_calls"([^>]*)>.*?</details>\n?',
    flags=re.DOTALL,
)
TOOL_CALLS_ATTRS_RE = re.compile(r'(\w+)="([^"]*)"')
REASONING_BLOCK_RE = re.compile(
    r'\n?<details type="reasoning"[^>]*>.*?</details>\n?',
    flags=re.DOTALL,
)


def format_reasoning_details(content: str, *, summary: str = "Thought") -> str:
    escaped = "\n".join(
        f"> {html.escape(line)}" if not line.startswith(">") else html.escape(line)
        for line in (content or "").splitlines()
    )
    return (
        '<details type="reasoning" done="true">\n'
        f"<summary>{html.escape(summary)}</summary>\n"
        f"{escaped}\n"
        "</details>\n"
    )


def format_tool_call_details(
    *,
    tool_id: str,
    name: str,
    args: dict[str, Any] | None,
    output: Any,
    is_error: bool = False,
    max_chars: int = 4000,
    ref: str = "",
) -> str:
    raw_result = output if isinstance(output, str) else str(output)
    truncated = len(raw_result) > max_chars
    preview = raw_result[:max_chars] if truncated else raw_result
    if truncated:
        preview += f"\n... (truncated, {len(raw_result) - max_chars} more chars)"
    escaped_args = html.escape(json.dumps(args or {}, ensure_ascii=False)) if args else ""
    escaped_result = html.escape(preview)
    error_attr = ' error="true"' if is_error else ""
    ref_attr = f' ref="{html.escape(ref)}"' if ref else ""
    return (
        f'<details type="tool_calls" done="true" id="{html.escape(tool_id)}" '
        f'name="{html.escape(name)}" arguments="{escaped_args}" '
        f'result="{escaped_result}" files="" embeds=""{error_attr}{ref_attr}>\n'
        "<summary>Tool Executed</summary>\n"
        "</details>\n"
    )


def parse_tool_call_attrs(raw_attrs: str) -> dict[str, str]:
    return {key: html.unescape(value) for key, value in TOOL_CALLS_ATTRS_RE.findall(raw_attrs or "")}


__all__ = [
    "REASONING_BLOCK_RE",
    "TOOL_CALLS_ATTRS_RE",
    "TOOL_CALLS_BLOCK_RE",
    "TOOL_CALLS_DETAILS_RE",
    "format_reasoning_details",
    "format_tool_call_details",
    "parse_tool_call_attrs",
]

# === owui_manifolds/shared/tools.py ===
import asyncio
import inspect
import json
import uuid
from dataclasses import dataclass, field
from typing import Any, Iterable, Literal


@dataclass
class SharedToolCall:
    call_id: str
    name: str
    arguments: dict[str, Any] = field(default_factory=dict)


@dataclass
class SharedToolResult:
    call_id: str
    name: str
    arguments: dict[str, Any]
    output_text: str
    response_payload: Any
    status: Literal["ok", "error", "timeout"]
    error_message: str | None = None
    files: list[Any] = field(default_factory=list)
    embeds: list[Any] = field(default_factory=list)


@dataclass
class SharedToolDefinition:
    name: str
    description: str
    parameters: dict[str, Any]


def normalize_parameters(schema: object) -> dict[str, Any]:
    return schema if isinstance(schema, dict) else {"type": "object", "properties": {}}


def iter_tool_definitions(registry: dict[str, Any] | None) -> list[SharedToolDefinition]:
    definitions: list[SharedToolDefinition] = []
    for entry in (registry or {}).values():
        if not isinstance(entry, dict):
            continue
        spec = entry.get("spec") if isinstance(entry.get("spec"), dict) else {}
        name = spec.get("name")
        if not isinstance(name, str) or not name:
            continue
        definitions.append(
            SharedToolDefinition(
                name=name,
                description=str(spec.get("description") or ""),
                parameters=normalize_parameters(spec.get("parameters")),
            )
        )
    return definitions


def candidate_tool_names(name: str) -> list[str]:
    candidates = [name]
    for sep in (":", "."):
        if sep in name:
            candidates.append(name.rsplit(sep, 1)[-1])
    seen: set[str] = set()
    return [candidate for candidate in candidates if candidate and not (candidate in seen or seen.add(candidate))]


async def dispatch_direct_tool(
    *,
    name: str,
    arguments: dict[str, Any],
    entry: dict[str, Any],
    event_call: Any | None,
    metadata: dict[str, Any] | None = None,
    call_id: str = "",
) -> SharedToolResult:
    if not callable(event_call):
        error = (
            f"Tool '{name}' is a direct tool-server tool and requires "
            "__event_call__ (browser round-trip) context, which is not "
            "available for this request."
        )
        return SharedToolResult(
            call_id=call_id,
            name=name,
            arguments=arguments,
            output_text=json.dumps({"error": error}, ensure_ascii=False),
            response_payload={"error": error},
            status="error",
            error_message="__event_call__ not available",
        )

    try:
        value = await event_call(
            {
                "type": "execute:tool",
                "data": {
                    "id": str(uuid.uuid4()),
                    "name": name,
                    "params": arguments,
                    "server": entry.get("server", {}),
                    "session_id": (metadata or {}).get("session_id"),
                },
            }
        )
    except Exception as exc:
        return SharedToolResult(
            call_id=call_id,
            name=name,
            arguments=arguments,
            output_text=f"Direct tool error: {exc}",
            response_payload={"error": str(exc)},
            status="error",
            error_message=str(exc),
        )

    output_text = value if isinstance(value, str) else json.dumps(value, ensure_ascii=False, default=str)
    payload = value if isinstance(value, dict) else {"result": value}
    return SharedToolResult(
        call_id=call_id,
        name=name,
        arguments=arguments,
        output_text=output_text,
        response_payload=payload,
        status="ok",
    )


class SharedOpenWebUIToolExecutor:
    def __init__(
        self,
        registry: dict[str, Any] | None,
        *,
        parallel: bool = True,
        event_call: Any | None = None,
        metadata: dict[str, Any] | None = None,
        timeout: float | None = None,
        process_tool_result: Any | None = None,
        request: Any | None = None,
        user: dict[str, Any] | None = None,
        namespace_resolution: bool = True,
    ):
        self._parallel = parallel
        self._event_call = event_call
        self._metadata = metadata or {}
        self._timeout = timeout
        self._process_tool_result = process_tool_result
        self._request = request
        self._user = user or {}
        self._namespace_resolution = namespace_resolution
        self._callables: dict[str, Any] = {}
        self._direct_entries: dict[str, dict[str, Any]] = {}
        for entry in (registry or {}).values():
            if not isinstance(entry, dict):
                continue
            spec = entry.get("spec") if isinstance(entry.get("spec"), dict) else {}
            name = spec.get("name")
            if not isinstance(name, str) or not name:
                continue
            fn = entry.get("callable")
            if fn is not None:
                self._callables[name] = fn
            elif entry.get("direct"):
                self._direct_entries[name] = entry

    def names(self) -> set[str]:
        return set(self._callables) | set(self._direct_entries)

    def iter_definitions(self) -> Iterable[SharedToolDefinition]:
        return iter_tool_definitions(
            {
                name: {"spec": {"name": name}}
                for name in sorted(self.names())
            }
        )

    def _names_for_lookup(self, name: str) -> list[str]:
        return candidate_tool_names(name) if self._namespace_resolution else [name]

    def _resolve(self, name: str) -> tuple[str, Any | None, dict[str, Any] | None]:
        for candidate in self._names_for_lookup(name):
            fn = self._callables.get(candidate)
            if fn is not None:
                return candidate, fn, None
            entry = self._direct_entries.get(candidate)
            if entry is not None:
                return candidate, None, entry
        return name, None, None

    async def execute(self, calls: list[SharedToolCall]) -> list[SharedToolResult]:
        if not self._parallel or len(calls) <= 1:
            return [await self._execute_one(call) for call in calls]

        seen: set[str] = set()
        has_duplicates = any((call.name in seen) or (seen.add(call.name) or False) for call in calls)
        if has_duplicates:
            return [await self._execute_one(call) for call in calls]

        return list(await asyncio.gather(*(self._execute_one(call) for call in calls)))

    async def _execute_callable(self, fn: Any, call: SharedToolCall) -> tuple[Any, list[Any], list[Any]]:
        async def invoke() -> Any:
            if inspect.iscoroutinefunction(fn):
                return await fn(**call.arguments)
            return await asyncio.to_thread(fn, **call.arguments)

        value = await asyncio.wait_for(invoke(), timeout=self._timeout) if self._timeout else await invoke()
        files: list[Any] = []
        embeds: list[Any] = []
        if self._process_tool_result and self._request:
            value, files, embeds = await self._process_tool_result(
                self._request,
                call.name,
                value,
                "pipe",
                metadata=self._metadata,
                user=self._user,
            )
        return value, files, embeds

    async def _execute_one(self, call: SharedToolCall) -> SharedToolResult:
        resolved_name, fn, direct_entry = self._resolve(call.name)
        if fn is None:
            if direct_entry is not None:
                return await dispatch_direct_tool(
                    name=resolved_name,
                    arguments=call.arguments,
                    entry=direct_entry,
                    event_call=self._event_call,
                    metadata=self._metadata,
                    call_id=call.call_id,
                )
            return SharedToolResult(
                call_id=call.call_id,
                name=call.name,
                arguments=call.arguments,
                output_text="Tool not found",
                response_payload={"error": "Tool not found"},
                status="error",
                error_message="Tool not found",
            )

        try:
            value, files, embeds = await self._execute_callable(fn, call)
            output_text = value if isinstance(value, str) else json.dumps(value, ensure_ascii=False, default=str)
            payload = value if isinstance(value, dict) else {"result": value}
            return SharedToolResult(
                call_id=call.call_id,
                name=call.name,
                arguments=call.arguments,
                output_text=output_text,
                response_payload=payload,
                status="ok",
                files=files,
                embeds=embeds,
            )
        except asyncio.TimeoutError:
            error = f"Tool '{call.name}' timed out"
            return SharedToolResult(
                call_id=call.call_id,
                name=call.name,
                arguments=call.arguments,
                output_text=error,
                response_payload={"error": error},
                status="timeout",
                error_message=error,
            )
        except Exception as exc:
            return SharedToolResult(
                call_id=call.call_id,
                name=call.name,
                arguments=call.arguments,
                output_text=f"Tool error: {exc}",
                response_payload={"error": str(exc)},
                status="error",
                error_message=str(exc),
            )


